public class Registro extends HttpServlet {
  private ListaUsuarios lista;

  protected void doPost(HttpServletRequest request, HttpServletResponse response) throws ServletException, IOException {
    Usuario usuario = getUsuario(request);
    request.setAttribute("currentUser", usuario);
    response.addCookie(new Cookie("userID", usuario.getId()));
    lista.changeCurrentUser(usuario);
    new Despachador().includePage(request, response, "servlet_3");
    new Despachador().includePage(request, response, "servlet_4");
    new Despachador().forwardPage(request, response, "/welcomeUser.jsp");
  }

  private Usuario getUsuario(HttpServletRequest request) {
    Usuario usuario = new Usuario();
    usuario.setNombre(request.getParameter("nombre"));
    usuario.setApellido(request.getParameter("apellido"));
    usuario.setId(request.getParameter("id"));
    usuario.setPassword(request.getParameter("pwd"));
    return usuario;
  }
}

public class RegistroUsuarios extends HttpServlet {
  private ListaUsuarios lista;

  protected void doPost(HttpServletRequest request, HttpServletResponse response) throws ServletException, IOException {
    procesaLista(request);
  }

  private void procesaLista(HttpServletRequest request) {
    Usuario actual = (Usuario) request.getAttribute("currentUser");
    lista.getLista().add(actual);
    request.setAttribute("listaUsuarios", lista);
    request.setAttribute("nUsers", lista.getNUsers());
  }
}

public class ListadoGeneral {
  private HashMap<String, Usuario> lista = new HashMap<>();

  public void setUsuario(Usuario usuario) {
    if (usuario != null && !lista.containsKey(usuario.getId())) {
      lista.put(usuario.getId(), usuario);
    }
  }
}
